 1→//! TUI entry point and main layout
 2→//!
 3→//! Contains the run() function to start the TUI and the ui() layout function.
 4→
 5→use anyhow::Result;
 6→use crossterm::{
 7→    event::{
 8→        DisableMouseCapture, EnableMouseCapture,
 9→        PopKeyboardEnhancementFlags,
10→    },
11→    execute,
12→    terminal::{disable_raw_mode, enable_raw_mode, EnterAlternateScreen, LeaveAlternateScreen},
13→};
