32→/// Run the TUI application
33→pub async fn run() -> Result<()> {
34→    enable_raw_mode()?;
35→    let mut stdout = io::stdout();
36→    execute!(stdout, EnterAlternateScreen, EnableMouseCapture)?;
37→
38→    // Enable Kitty keyboard protocol so Shift+Enter is distinguishable from Enter.
39→    // DISAMBIGUATE alone makes Enter → CSI 13u, Shift+Enter → CSI 13;2u.
40→    // REPORT_EVENT_TYPES adds Press/Release/Repeat — only Press is processed.
41→    // We intentionally omit REPORT_ALL_KEYS because it makes Shift+letter
42→    // arrive as (SHIFT, Char('1')) instead of (NONE, Char('!')), breaking
43→    // secondary character input (!, @, #, etc.).
44→    //
45→    // Disabled on Windows — Windows Terminal claims Kitty support but the
46→    // implementation conflicts with mouse capture: scroll/arrow CSI sequences
47→    // leak through as raw text (e.g. "[A[B" appearing in the input box).
48→    #[cfg(not(target_os = "windows"))]
49→    let kbd_enhanced = execute!(
50→        stdout,
51→        PushKeyboardEnhancementFlags(
52→            KeyboardEnhancementFlags::DISAMBIGUATE_ESCAPE_CODES
53→                | KeyboardEnhancementFlags::REPORT_EVENT_TYPES
54→        )
55→    ).is_ok();
56→    #[cfg(target_os = "windows")]
57→    let kbd_enhanced = false;
58→
59→    let backend = CrosstermBackend::new(stdout);
60→    let mut terminal = Terminal::new(backend)?;

input.new_string:
event::{
    DisableMouseCapture, EnableMouseCapture,
    KeyboardEnhancementFlags, PopKeyboardEnhancementFlags,
    PushKeyboardEnhancementFlags,
},

input.old_string:
event::{
    DisableMouseCapture, EnableMouseCapture,
    PopKeyboardEnhancementFlags,
},

