   1→//! UI hint generators
   2→//!
   3→//! Functions that produce display strings for title bars, footers, and help
   4→//! overlays by reading key labels from the binding arrays. Draw functions call
   5→//! these instead of hardcoding hint strings.
   6→
   7→use super::types::{Action, HelpSection, Keybinding};
   8→use super::bindings::*;
   9→
  10→/// Platform-appropriate modifier prefix for Ctrl
  11→fn plat_ctrl(key: &str) -> String {
  12→    if cfg!(target_os = "macos") { format!("⌃{}", key) } else { format!("Ctrl+{}", key) }
  13→}
  14→
  15→/// Platform-appropriate modifier prefix for Alt
  16→fn plat_alt(key: &str) -> String {
  17→    if cfg!(target_os = "macos") { format!("⌥{}", key) } else { format!("Alt+{}", key) }
  18→}
  19→
  20→/// Platform-appropriate modifier prefix for Shift
  21→fn plat_shift(key: &str) -> String {
  22→    if cfg!(target_os = "macos") { format!("⇧{}", key) } else { format!("Shift+{}", key) }
  23→}
  24→
  25→/// Generate help sections from binding definitions
  26→/// Note: Terminal and Input bindings are shown in their own title bars, not here
  27→pub fn help_sections() -> Vec<HelpSection> {
  28→    vec![
  29→        HelpSection { title: "Filetree", bindings: &FILE_TREE },
  30→        HelpSection { title: "Viewer", bindings: &VIEWER },
  31→        HelpSection { title: "Edit Mode", bindings: &EDIT_MODE },
  32→        HelpSection { title: "Session", bindings: &SESSION },
  33→    ]
  34→}
  35→
  36→/// Title + hints for prompt input (type mode).
  37→/// Returns (short_label, full_title_with_hints, just_the_hints).
  38→/// Callers use full title if it fits, otherwise short label in border + hints as inner row.
  39→pub fn prompt_type_title() -> (String, String, String) {
  40→    let esc = find_key_for_action(&INPUT, Action::ExitPromptMode).unwrap_or("Esc".into());
  41→    let submit = find_key_for_action(&INPUT, Action::Submit).unwrap_or("Enter".into());
  42→    let cancel = find_key_for_action(&GLOBAL, Action::CancelClaude).unwrap_or(plat_ctrl("c"));
  43→    let (hprev, hnext) = find_key_pair(&INPUT, Action::HistoryPrev, Action::HistoryNext, "↑", "↓");
  44→    let dw = find_key_for_action(&INPUT, Action::DeleteWord).unwrap_or(plat_ctrl("w"));
  45→    let stt = find_key_for_action(&INPUT, Action::ToggleStt).unwrap_or(plat_ctrl("s"));
  46→    let presets = find_key_for_action(&INPUT, Action::PresetPrompts).unwrap_or(plat_alt("p"));
  47→    let shift_enter = plat_shift("Enter");
  48→    let alt_arrows = if cfg!(target_os = "macos") {
  49→        "⌥←/→:word".to_string()
  50→    } else {
  51→        "Alt+ ← / → :word".to_string()
  52→    };
  53→    let hints = format!(
  54→        "{}:exit | {}:submit | {}:newline | {}:cancel agent | {}/{}:history | {} | {}:del wrd | {}:speech | {}:presets",
  55→        esc, submit, shift_enter, cancel, hprev, hnext, alt_arrows, dw, stt, presets
  56→    );
  57→    let label = " PROMPT ".to_string();
  58→    let full = format!(" PROMPT ({}) ", hints);
  59→    (label, full, hints)
  60→}
  61→
  62→/// Title + hints for command mode — shows ALL global keybindings.
  63→/// Returns (short_label, full_title_with_hints, just_the_hints).
  64→pub fn prompt_command_title() -> (String, String, String) {
  65→    let p = find_key_for_action(&GLOBAL, Action::EnterPromptMode).unwrap_or("p".into());
  66→    let t = find_key_for_action(&GLOBAL, Action::ToggleTerminal).unwrap_or("T".into());
  67→    let g = find_key_for_action(&GLOBAL, Action::OpenGitActions).unwrap_or("G".into());
  68→    let h = find_key_for_action(&GLOBAL, Action::OpenHealth).unwrap_or("H".into());
  69→    let help = find_key_for_action(&GLOBAL, Action::ToggleHelp).unwrap_or("?".into());
  70→    let cancel = find_key_for_action(&GLOBAL, Action::CancelClaude).unwrap_or(plat_ctrl("c"));
  71→    let quit = find_key_for_action(&GLOBAL, Action::Quit).unwrap_or(plat_ctrl("q"));
  72→    let dump = find_key_for_action(&GLOBAL, Action::DumpDebug).unwrap_or(plat_ctrl("d"));
  73→    let run = find_key_for_action(&GLOBAL, Action::RunCommand).unwrap_or("R".into());
  74→    let (wt_prev, wt_next) = find_key_pair(&GLOBAL, Action::WorktreeTabPrev, Action::WorktreeTabNext, "[", "]");
  75→    let wt_add = find_key_for_action(&GLOBAL, Action::AddWorktree).unwrap_or("w".into());
  76→    let wt_archive = find_key_for_action(&GLOBAL, Action::ToggleArchiveWorktree).unwrap_or(plat_alt("a"));
  77→    let wt_delete = find_key_for_action(&GLOBAL, Action::DeleteWorktree).unwrap_or(plat_alt("d"));
  78→    let focus_hint = if cfg!(target_os = "macos") { "Tab/⇧Tab" } else { "Tab/Shift+Tab" };
  79→    let hints = format!(
  80→        "{}:PROMPT | {}:TERMINAL | {}:run | {}:Git | {}:Health | {}/{}:worktree | {}:add wt | {}:archive wt | {}:del wt | {}:focus | {}:cancel agent | {}:quit | {}:dump | {}:help",
  81→        p, t, run, g, h, wt_prev, wt_next, wt_add, wt_archive, wt_delete, focus_hint, cancel, quit, dump, help
  82→    );
  83→    let label = " COMMAND ".to_string();
  84→    let full = format!(" COMMAND ({}) ", hints);
  85→    (label, full, hints)
  86→}
