  88→/// Title + hints for terminal type mode.
  89→/// Returns (short_label, full_title, hints).
  90→pub fn terminal_type_title() -> (String, String, String) {
  91→    let esc = find_key_for_action(&TERMINAL, Action::Escape).unwrap_or("Esc".into());
  92→    let hints = format!("{}:exit", esc);
  93→    (" TERMINAL ".to_string(), format!(" TERMINAL ({}) ", hints), hints)
  94→}
  95→
  96→/// Title + hints for terminal command mode.
  97→/// Returns (short_label, full_title, hints).
  98→pub fn terminal_command_title() -> (String, String, String) {
  99→    let t = find_key_for_action(&TERMINAL, Action::EnterTerminalType).unwrap_or("t".into());
 100→    let p = find_key_for_action(&TERMINAL, Action::EnterPromptMode).unwrap_or("p".into());
 101→    let esc = find_key_for_action(&TERMINAL, Action::Escape).unwrap_or("Esc".into());
 102→    let (down, up) = find_key_pair(&TERMINAL, Action::NavDown, Action::NavUp, "j", "k");
 103→    let (pdn, pup) = find_key_pair(&TERMINAL, Action::PageDown, Action::PageUp, "J", "K");
 104→    let alt_up = if cfg!(target_os = "macos") { "⌥↑" } else { "Alt+↑" };
 105→    let alt_dn = if cfg!(target_os = "macos") { "⌥↓" } else { "Alt+↓" };
 106→    let (top, bot) = find_key_pair(&TERMINAL, Action::GoToTop, Action::GoToBottom, alt_up, alt_dn);
 107→    let (rup, rdn) = find_key_pair(&TERMINAL, Action::ResizeUp, Action::ResizeDown, "+", "-");
 108→    let hints = format!(
 109→        "{}:type | {}:prompt | {}:close | {}/{}:scroll | {}/{}:page | {}/{}:top/bottom | {}/{}:resize",
 110→        t, p, esc, down, up, pdn, pup, top, bot, rup, rdn
 111→    );
 112→    (" TERMINAL ".to_string(), format!(" TERMINAL ({}) ", hints), hints)
 113→}
 114→
 115→/// Title + hints for terminal scrolled mode.
 116→/// Returns (short_label, full_title, hints).
 117→pub fn terminal_scroll_title(scroll: usize) -> (String, String, String) {
 118→    let (down, up) = find_key_pair(&TERMINAL, Action::NavDown, Action::NavUp, "j", "k");
 119→    let (pdn, pup) = find_key_pair(&TERMINAL, Action::PageDown, Action::PageUp, "J", "K");
 120→    let top = find_key_for_action(&TERMINAL, Action::GoToTop).unwrap_or(plat_alt("↑"));
 121→    let bot = find_key_for_action(&TERMINAL, Action::GoToBottom).unwrap_or(plat_alt("↓"));
 122→    let t = find_key_for_action(&TERMINAL, Action::EnterTerminalType).unwrap_or("t".into());
 123→    let esc = find_key_for_action(&TERMINAL, Action::Escape).unwrap_or("Esc".into());
 124→    let hints = format!(
 125→        "{}/{}:scroll | {}/{}:page | {}:top | {}:bottom | {}:type | {}:close",
 126→        down, up, pdn, pup, top, bot, t, esc
 127→    );
 128→    let label = format!(" TERMINAL [{}↑] ", scroll);
 129→    let full = format!(" TERMINAL [{}↑] ({}) ", scroll, hints);
 130→    (label, full, hints)
 131→}
