 157→/// Git Actions panel — action key+description pairs for the action list labels.
 158→/// Context-aware: main branch shows pull+commit+push, feature shows squash-merge+commit+push.
 159→pub fn git_actions_labels(is_on_main: bool) -> Vec<(String, &'static str)> {
 160→    let actions: &[Action] = if is_on_main {
 161→        &[Action::GitPull, Action::GitCommit, Action::GitPush]
 162→    } else {
 163→        &[Action::GitSquashMerge, Action::GitRebase, Action::GitCommit, Action::GitPush]
 164→    };
 165→    actions.iter()
 166→        .filter_map(|&a| {
 167→            GIT_ACTIONS.iter().find(|b| b.action == a).map(|b| (b.primary.display(), b.description))
 168→        })
 169→        .collect()
 170→}
