 172→/// Git Actions panel footer hints
 173→pub fn git_actions_footer() -> String {
 174→    let tab = find_key_for_action(&GIT_ACTIONS, Action::GitToggleFocus).unwrap_or("Tab".into());
 175→    let enter = find_key_for_action(&GIT_ACTIONS, Action::Confirm).unwrap_or("Enter".into());
 176→    let refresh = find_key_for_action(&GIT_ACTIONS, Action::GitRefresh).unwrap_or("R".into());
 177→    let esc = find_key_for_action(&GIT_ACTIONS, Action::Escape).unwrap_or("Esc".into());
 178→    let (prev, next) = find_key_pair(&GIT_ACTIONS, Action::GitPrevWorktree, Action::GitNextWorktree, "[", "]");
 179→    let (pprev, pnext) = find_key_pair(&GIT_ACTIONS, Action::GitPrevPage, Action::GitNextPage, "{", "}");
 180→    format!("{}:cycle panes | {}:exec/view | {}:refresh | {}/{}:wt | {}/{}:page | {}:close", tab, enter, refresh, prev, next, pprev, pnext, esc)
 181→}
