 183→/// Projects panel browse-mode hint pairs: (key_display, label) for colored Span rendering.
 184→/// Caller gets `has_project` to conditionally include Esc:close.
 185→pub fn projects_browse_hint_pairs(has_project: bool) -> Vec<(String, &'static str)> {
 186→    let mut v = vec![
 187→        (find_key_for_action(&PROJECTS_BROWSE, Action::Confirm).unwrap_or("Enter".into()), "open"),
 188→        (find_key_for_action(&PROJECTS_BROWSE, Action::ProjectsAdd).unwrap_or("a".into()), "add"),
 189→        (find_key_for_action(&PROJECTS_BROWSE, Action::ProjectsDelete).unwrap_or("d".into()), "delete"),
 190→        (find_key_for_action(&PROJECTS_BROWSE, Action::ProjectsRename).unwrap_or("n".into()), "name"),
 191→        (find_key_for_action(&PROJECTS_BROWSE, Action::ProjectsInit).unwrap_or("i".into()), "init"),
 192→    ];
 193→    if has_project { v.push(("Esc".into(), "close")); }
 194→    v.push((find_key_for_action(&PROJECTS_BROWSE, Action::Quit).unwrap_or("⌃Q".into()), "quit"));
 195→    v
 196→}
