 219→/// Find the display key for a given action in a binding list
 220→pub fn find_key_for_action(bindings: &[Keybinding], action: Action) -> Option<String> {
 221→    bindings.iter()
 222→        .find(|b| b.action == action)
 223→        .map(|b| b.primary.display())
 224→}
 225→
 226→/// Find a pair of keys for two related actions (e.g., NavDown/NavUp → "j"/"k")
 227→pub fn find_key_pair(bindings: &[Keybinding], a: Action, b: Action, da: &str, db: &str) -> (String, String) {
 228→    (
 229→        find_key_for_action(bindings, a).unwrap_or_else(|| da.into()),
 230→        find_key_for_action(bindings, b).unwrap_or_else(|| db.into()),
 231→    )
 232→}
