 97→pub fn lookup_health_action(
 98→    tab: crate::app::types::HealthTab,
 99→    modifiers: KeyModifiers,
100→    code: KeyCode,
101→) -> Option<Action> {
102→    for b in &HEALTH_SHARED { if b.matches(modifiers, code) { return Some(b.action); } }
103→    let tab_bindings: &[Keybinding] = match tab {
104→        crate::app::types::HealthTab::GodFiles => &HEALTH_GOD_FILES,
105→        crate::app::types::HealthTab::Documentation => &HEALTH_DOCS,
106→    };
107→    for b in tab_bindings { if b.matches(modifiers, code) { return Some(b.action); } }
108→    None
