   1→//! Core keybinding types
   2→//!
   3→//! Defines the fundamental data structures used across the keybinding system:
   4→//! `KeyCombo`, `Action`, `Keybinding`, and `HelpSection`.
   5→
   6→use crossterm::event::{KeyCode, KeyModifiers};
   7→
   8→/// A key combination (modifier + key)
   9→#[derive(Debug, Clone, Copy, PartialEq, Eq)]
  10→pub struct KeyCombo {
  11→    pub modifiers: KeyModifiers,
  12→    pub code: KeyCode,
  13→}
  14→
  15→impl KeyCombo {
  16→    pub const fn new(modifiers: KeyModifiers, code: KeyCode) -> Self {
  17→        Self { modifiers, code }
  18→    }
  19→
  20→    pub const fn plain(code: KeyCode) -> Self {
  21→        Self { modifiers: KeyModifiers::NONE, code }
  22→    }
  23→
  24→    pub const fn shift(code: KeyCode) -> Self {
  25→        Self { modifiers: KeyModifiers::SHIFT, code }
  26→    }
  27→
  28→    pub const fn ctrl(code: KeyCode) -> Self {
  29→        Self { modifiers: KeyModifiers::CONTROL, code }
  30→    }
  31→
  32→    pub const fn alt(code: KeyCode) -> Self {
  33→        Self { modifiers: KeyModifiers::ALT, code }
  34→    }
  35→
  36→    #[cfg(target_os = "macos")]
  37→    pub const fn cmd(code: KeyCode) -> Self {
  38→        Self { modifiers: KeyModifiers::SUPER, code }
  39→    }
  40→
  41→    /// Check if key event matches this combo
  42→    #[inline]
  43→    pub fn matches(&self, modifiers: KeyModifiers, code: KeyCode) -> bool {
  44→        if self.modifiers == modifiers && self.code == code { return true; }
  45→        // Shifted-symbol bindings: characters like ?, !, @, #, etc. are
  46→        // produced by pressing Shift+<key>. On macOS, crossterm typically
  47→        // delivers these as (NONE, Char('?')). On Windows, crossterm
  48→        // delivers (SHIFT, Char('?')). When a binding uses plain(Char('?')),
  49→        // also accept SHIFT modifier if the char matches — the SHIFT is
  50→        // implicit in producing the character itself.
  51→        if self.modifiers == KeyModifiers::NONE
  52→            && modifiers == KeyModifiers::SHIFT
  53→            && self.code == code
  54→        {
  55→            if let KeyCode::Char(c) = code {
  56→                // Only for non-alpha chars — Shift+letter has separate handling below
  57→                if !c.is_ascii_alphabetic() { return true; }
  58→            }
  59→        }
  60→        // Shift+letter bindings use shift(Char('G')) but crossterm delivers
  61→        // uppercase chars inconsistently depending on terminal + Kitty flags:
  62→        //   - (NONE, Char('G'))  — no Kitty or legacy terminals
  63→        //   - (SHIFT, Char('G')) — some Kitty implementations
  64→        //   - (SHIFT, Char('g')) — DISAMBIGUATE without REPORT_ALL_KEYS
  65→        // Match all three against a SHIFT + uppercase char binding.
  66→        // Shift+letter bindings: crossterm delivers uppercase as either
  67→        //   (NONE, Char('G')) or (SHIFT, Char('G')) or (SHIFT, Char('g'))
  68→        // but NEVER (NONE, Char('g')) for a shifted press. So only match
  69→        // when the pressed char is already uppercase (NONE modifier) or
  70→        // SHIFT is held — reject plain lowercase to avoid t matching T.
  71→        // Shift+letter bindings: crossterm delivers uppercase chars
  72→        // inconsistently depending on terminal + Kitty flags. Generalized
  73→        // for pure SHIFT and combined modifiers (e.g. CTRL+SHIFT+C).
  74→        if self.modifiers.contains(KeyModifiers::SHIFT) {
  75→            if let KeyCode::Char(c) = self.code {
  76→                if c.is_ascii_uppercase() {
  77→                    let other_mods = self.modifiers.difference(KeyModifiers::SHIFT);
  78→                    if let KeyCode::Char(pressed) = code {
  79→                        // (other_mods | SHIFT, any case) — SHIFT explicitly flagged
  80→                        if modifiers.contains(KeyModifiers::SHIFT)
  81→                            && modifiers.difference(KeyModifiers::SHIFT) == other_mods
  82→                            && pressed.to_ascii_uppercase() == c
  83→                        {
  84→                            return true;
  85→                        }
  86→                        // (other_mods, uppercase) — legacy terminals omit SHIFT flag
  87→                        if modifiers == other_mods && pressed == c {
  88→                            return true;
  89→                        }
  90→                    }
  91→                }
  92→            }
  93→        }
  94→        false
  95→    }
  96→
  97→    /// Platform-appropriate display string
  98→    /// macOS: ⌃⌥⇧⌘ symbols. Windows/Linux: Ctrl+Alt+Shift+ text labels.
  99→    pub fn display(&self) -> String {
 100→        let mut s = String::new();
 101→
 102→        #[cfg(target_os = "macos")]
 103→        {
 104→            if self.modifiers.contains(KeyModifiers::CONTROL) { s.push('⌃'); }
 105→            if self.modifiers.contains(KeyModifiers::ALT) { s.push('⌥'); }
 106→            // Show ⇧ for non-char keys always, and for char keys when
 107→            // combined with other modifiers (e.g. ⌃⇧C vs just G)
 108→            if self.modifiers.contains(KeyModifiers::SHIFT) {
 109→                let has_other_mods = self.modifiers != KeyModifiers::SHIFT;
 110→                if !matches!(self.code, KeyCode::Char(_)) || has_other_mods {
 111→                    s.push('⇧');
 112→                }
 113→            }
 114→            if self.modifiers.contains(KeyModifiers::SUPER) { s.push('⌘'); }
 115→        }
 116→
 117→        #[cfg(not(target_os = "macos"))]
 118→        {
 119→            if self.modifiers.contains(KeyModifiers::CONTROL) { s.push_str("Ctrl+"); }
 120→            if self.modifiers.contains(KeyModifiers::ALT) { s.push_str("Alt+"); }
 121→            if self.modifiers.contains(KeyModifiers::SHIFT) {
 122→                let has_other_mods = self.modifiers != KeyModifiers::SHIFT;
 123→                if !matches!(self.code, KeyCode::Char(_)) || has_other_mods {
 124→                    s.push_str("Shift+");
 125→                }
 126→            }
 127→        }
 128→
 129→        match self.code {
 130→            KeyCode::Char(' ') => s.push_str("Space"),
 131→            KeyCode::Char(c) => s.push(c),
 132→            KeyCode::Enter => s.push_str("Enter"),
 133→            KeyCode::Esc => s.push_str("Esc"),
 134→            KeyCode::Tab => s.push_str("Tab"),
 135→            KeyCode::BackTab => s.push_str("Tab"),
 136→            KeyCode::Backspace => s.push('⌫'),
 137→            KeyCode::Delete => s.push('⌦'),
 138→            KeyCode::Up => s.push('↑'),
 139→            KeyCode::Down => s.push('↓'),
 140→            KeyCode::Left => s.push('←'),
 141→            KeyCode::Right => s.push('→'),
 142→            KeyCode::Home => s.push_str("Home"),
 143→            KeyCode::End => s.push_str("End"),
 144→            KeyCode::PageUp => s.push_str("PgUp"),
 145→            KeyCode::PageDown => s.push_str("PgDn"),
 146→            _ => s.push_str(&format!("{:?}", self.code)),
 147→        }
 148→        s
 149→    }
 150→}
