 290→/// A keybinding with one or more key alternatives
 291→#[derive(Debug, Clone)]
 292→pub struct Keybinding {
 293→    /// Primary key combo
 294→    pub primary: KeyCombo,
 295→    /// Alternative key combos (e.g., j AND Down for same action)
 296→    pub alternatives: &'static [KeyCombo],
 297→    /// Description for help dialog
 298→    pub description: &'static str,
 299→    /// Action identifier
 300→    pub action: Action,
 301→    /// When true, help panel merges this binding with the NEXT one onto a single line.
 302→    /// Use for counterpart pairs like up/down, next/prev, expand/collapse.
 303→    pub pair_with_next: bool,
 304→}
 305→
 306→impl Keybinding {
 307→    pub const fn new(primary: KeyCombo, description: &'static str, action: Action) -> Self {
 308→        Self { primary, alternatives: &[], description, action, pair_with_next: false }
 309→    }
 310→
 311→    pub const fn with_alt(
 312→        primary: KeyCombo,
 313→        alternatives: &'static [KeyCombo],
 314→        description: &'static str,
 315→        action: Action,
 316→    ) -> Self {
 317→        Self { primary, alternatives, description, action, pair_with_next: false }
 318→    }
 319→
 320→    /// Mark this binding to merge with the next one on a single help line
 321→    pub const fn paired(mut self) -> Self {
 322→        self.pair_with_next = true;
 323→        self
 324→    }
 325→
 326→    /// Check if any key combo matches
 327→    #[inline]
 328→    pub fn matches(&self, modifiers: KeyModifiers, code: KeyCode) -> bool {
 329→        self.primary.matches(modifiers, code)
 330→            || self.alternatives.iter().any(|k| k.matches(modifiers, code))
 331→    }
 332→
 333→    /// Display string combining primary and alternatives (e.g., "j/↓").
 334→    /// Skips macOS ⌥+letter unicode fallback chars (®, π, †, etc.) — those are
 335→    /// internal matching alternatives, not meaningful to show in the help panel.
 336→    pub fn display_keys(&self) -> String {
 337→        if self.alternatives.is_empty() {
 338→            return self.primary.display();
 339→        }
 340→        let mut s = self.primary.display();
 341→        for alt in self.alternatives {
 342→            // Skip bare unicode chars produced by macOS ⌥+letter (not ASCII, no modifiers)
 343→            if let KeyCode::Char(c) = alt.code {
 344→                if !c.is_ascii() && alt.modifiers == KeyModifiers::NONE { continue; }
 345→            }
 346→            s.push('/');
 347→            s.push_str(&alt.display());
 348→        }
 349→        s
 350→    }
 351→}
